INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('8f2727bb-47e9-53bd-bc1a-e8e4dc7a793b', '8b3242aa-721e-485b-a282-9f1917c6f65d', 'It takes ___ long time to complete the marathon.', '完成馬拉松需要一段很長的時間。', 'a', 'some', 'any', 'each', 'a 為不定冠詞，用於單數可數名詞前，表示「一個」或「一段」。', 'a 代表 one (一個)。', '2026-07-05 09:30:25', '2026-07-05 09:30:25'),
('b5778c86-8e23-5450-b804-28a525fa478b', 'c932dae6-21bd-4dc9-b4fc-f2986be56b0e', 'I have ___ of homework to do tonight.', '我今晚有很多功課要做。', 'a lot', 'many', 'much', 'some', 'a lot 表示「很多」，搭配 of 使用時，後方可接名詞。', 'a lot of → 很多', '2026-07-06 12:20:34', '2026-07-06 12:20:34'),
('a6bf62fc-054c-5869-9cab-ff773e03b007', '494900a4-0160-4783-bddd-1ed342cd5be2', 'The ___ professor often forgets where he put his glasses, making it hard for him to teach effectively.', '那位心不在焉的教授經常忘記眼鏡放在哪裡，導致他很難有效地教學。', 'absentminded', 'energetic', 'punctual', 'cautious', '由 absent (不在場的) 與 mind (心靈/思想) 組成，字面意思為「心思不在現場」。', '記住 absent 是「缺席」，mind 是「心」，缺席了心思 → 心不在焉。', '2026-07-06 16:14:02', '2026-07-06 16:14:02'),
('010b9ebf-c653-5a7e-b0df-2e9af3987a97', '15a40787-2830-45fa-93b3-9ea0f1334e48', 'The witness provided a detailed ___ of the accident to the police.', '目擊者向警方提供了事故的詳細描述。', 'account', 'amount', 'manner', 'degree', 'ac- (趨向) + count (計算) → 將事情像清點數字一樣整理出來 → 說明、描述或帳目。', '想像你在 count (計算) 事情發生的順序，一項一項說清楚，就是在做一個 account (描述/說明)。', '2026-07-06 16:55:42', '2026-07-06 16:55:42'),
('32539ed8-18cd-5cfb-b7a4-19f7ac83f577', '376db94f-a897-4048-9ac5-2f3de0a4e58c', 'The receipt serves as an ___ that your transaction has been successfully processed.', '收據作為您的交易已成功處理的確認。', 'acknowledgement', 'adjustment', 'appointment', 'assessment', 'acknowledge (承認/確認) + -ment (名詞字尾) → 表示「承認」或「確認」的行為。', 'know (知道) → 讓對方知道這件事 → 承認、確認。', '2026-07-06 17:13:44', '2026-07-06 17:13:44'),
('c792aa64-348d-5704-ab6e-1d369315792b', 'da064c91-6cbd-42a1-9e71-b4305b0dba71', 'The two runners will ___ sprinting and walking to build up their stamina.', '這兩位跑者將交替進行衝刺與行走，以建立耐力。', 'alternate', 'combine', 'practice', 'avoid', '字根 alter 意為「改變」，在此動詞用法中表示「交替」或「輪流」。', '想像兩個人在不斷「改變 (alter)」位置，所以需要「輪流 (alternate)」交換。', '2026-07-06 20:22:42', '2026-07-06 20:22:42'),
('c378ae4e-4a9d-512f-ba23-1eed4e01a683', 'b49196ee-3cf8-4077-8592-1eca5b10094b', 'The weather was terrible, but they decided to go hiking ___.', '天氣很糟糕，但他們還是決定去健行。', 'anyway', 'upstairs', 'nowadays', 'together', 'any (任何) + way (方式/道路)', '不管在任何 (any) 道路 (way) 上，regardless of the path，就是 anyway。', '2026-07-06 22:37:18', '2026-07-06 22:37:18'),
('c2f34ffa-5029-539a-96c4-433660dfdd4f', 'be59ed5b-c5e7-4a92-bf01-cbcdee9a62c3', 'The secret plot to ___ the political leader was foiled by the police just hours before the ceremony.', '在典禮開始前幾小時，警方挫敗了暗殺這位政治領袖的秘密陰謀。', 'assassinate', 'celebrate', 'liberate', 'nominate', 'assassin (暗殺者) + -ate (動詞字尾) → 暗殺。', '想像一個 assassin (暗殺者) 用刀「ate (吃)」掉目標的生命 → 暗殺。', '2026-07-07 00:54:45', '2026-07-07 00:54:45'),
('9c3e8959-646e-58bc-b900-8bd5243a3e6b', '893c16d5-9c3c-413a-ad3a-c240e4fee897', 'My brother loves to play ___ with his friends on weekends.', '我哥哥週末喜歡和他的朋友們一起打羽毛球。', 'badminton', 'basketball', 'baseball', 'soccer', 'badminton 源自於 battledore (球拍) 與 shuttlecock (羽毛球) 的縮寫結合。', '看到 badminton 就聯想到在打羽毛球。', '2026-07-07 01:50:13', '2026-07-07 01:50:13'),
('81337801-4d60-5e6a-81ec-23f2e80ec46b', '1086b30e-78a0-4127-897a-2560c0709610', 'We need a bat and a ball to play ___.', '我們需要一支球棒和一顆球來打棒球。', 'baseball', 'basketball', 'soccer', 'tennis', 'base (基礎/基地) + ball (球) → 棒球', '想像球員站在 base (壘包) 上玩 ball (球) → baseball。', '2026-07-07 02:29:05', '2026-07-07 02:29:05'),
('6f1b43e1-d6f0-5d93-ac49-4aa7bf4310e7', '92168815-baed-4664-84aa-cc2a5a31e220', 'The sailors had to ___ their boat on the sand.', '水手們必須將船拖上沙灘。', 'beach', 'drive', 'cook', 'watch', '動詞 (v.)：將(船等)拖上岸。', '想像船被「放到沙灘上」的動作。', '2026-07-07 02:41:54', '2026-07-07 02:41:54'),
('141e3169-a494-591c-bef4-78c63d8c9bdb', '9ad79bc9-67d3-4097-914f-562ebc654d5e', 'I am very tired, so I want to lie on my ___ and sleep.', '我很累，所以我想要躺在我的床上睡覺。', 'bed', 'desk', 'chair', 'wall', 'bed 為名詞，指用來睡覺的床。', 'bed → sleep (床 → 睡覺)', '2026-07-07 02:58:57', '2026-07-07 02:58:57'),
('ab29f6e5-3ae6-5b06-869b-2db147789aa7', '2b7ae480-aa37-4256-a677-74ed54f87d83', 'The sun is very ___ today, so I need my sunglasses.', '今天太陽非常明亮，所以我需要戴上墨鏡。', 'bright', 'heavy', 'noisy', 'hungry', 'bright 是形容詞，用來形容光線明亮或人很聰明。', '想像太陽亮到讓人想躲起來 → bright。', '2026-07-07 08:22:43', '2026-07-07 08:22:43'),
('0326857a-64d3-5684-8762-a4871554b47b', 'bbb2fcee-f431-417f-9611-641469dcd9d1', 'He is ___ a child, yet he is very responsible.', '他僅僅是一個孩子，卻非常負責。', 'but', 'very', 'quite', 'highly', 'adv. (副詞) 用於強調「僅僅」、「只」的意思。', '在文學或正式用法中，but 可當作「僅僅」來使用 → but', '2026-07-05 14:07:23', '2026-07-05 14:07:23'),
('8e3a0b88-a8f2-5545-bfd4-d2c794ffbeef', '6caf5415-789b-4962-912b-1129e21aa239', 'My favorite ___ is blue because it looks like the ocean.', '我最喜歡的顏色是藍色，因為它看起來像大海。', 'color', 'sound', 'smell', 'height', 'color 源自拉丁語，指色彩或顏色。', '記住 color 是顏色，例如 coloring book 就是著色本。', '2026-07-07 05:12:47', '2026-07-07 05:12:47'),
('598997ab-a612-56fa-965f-e362a6480bb7', 'c8ab73e5-ae8a-42dd-a961-92b45c4478b9', 'He is a ___ friend to everyone in the class.', '他是班上每個人親愛的朋友。', 'dear', 'fast', 'cold', 'loud', 'dear (adj.) 表示「親愛的」或「珍貴的」。', '想著 dear 像 deer (鹿)，鹿是非常可愛、親愛的動物。', '2026-07-07 03:00:49', '2026-07-07 03:00:49'),
('6b33319b-cda7-53e9-9ec6-709b535f2237', '8cffd79d-6e9b-4911-aca9-b616611dde98', 'The ___ is a forest animal with beautiful antlers.', '這隻鹿是森林裡的動物，擁有美麗的鹿角。', 'deer', 'bird', 'fish', 'pig', 'deer 是單數與複數同形的單字，指具有鹿角的草食性動物。', '看到 antlers (鹿角) → 想到 deer (鹿)。', '2026-07-07 03:12:21', '2026-07-07 03:12:21'),
('1421da6f-3065-58f8-a41b-d432b78a9573', 'af5bcc0d-d5fe-48ec-bc42-bb72cf37982a', 'Please put the letter in the ___ before you mail it.', '請在寄出這封信之前，把信放進信封裡。', 'envelope', 'box', 'bag', 'folder', 'en- 表示「在...之中」或「包圍」的意思。', '想像信封把信件包起來的樣子。', '2026-07-07 04:10:10', '2026-07-07 04:10:10');
